import Autumn from 'autumn-js';

const autumn = new Autumn({ secretKey: process.env.AUTUMN_SECRET_KEY });

export async function checkApiQuota(req, res, next) {
  const customerId = req.headers['x-customer-id'];

  if (!customerId) {
    return res.status(400).json({ error: 'Missing customer ID' });
  }

  const { allowed } = await autumn.check({
    customerId,
    featureId: 'api-requests',
  });

  if (!allowed) {
    return res.status(429).json({ error: 'API quota exceeded', allowed: false });
  }

  await autumn.track({
    customerId,
    featureId: 'api-requests',
    value: 1,
  });

  next();
}

import { Router } from 'express';
import { checkApiQuota } from '../middleware/rateLimit.js';

const router = Router();

router.post('/process', checkApiQuota, (req, res) => {
  const customerId = req.headers['x-customer-id'];
  const { payload } = req.body;

  res.json({
    result: 'processed',
    payload: payload,
    customerId: customerId,
  });
});

export default router;
